import React, { useEffect, useState } from "react";
import axios from "axios";
import "./LabSearch.css";

const LabSearch = ({ goBack }) => {
  const [lab, setLab] = useState(""); // Selected lab
  const [labList, setLabList] = useState([]); // List of available labs
  const [day, setDay] = useState("Monday");
  const [period, setPeriod] = useState("1");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {
    // Fetch the lab list from backend
    axios.get("http://localhost:5000/api/lab-list")
      .then((res) => {
        setLabList(res.data);
        if (res.data.length > 0) {
          setLab(res.data[0].name); // Default to first lab
        }
      })
      .catch((err) => console.error("Error fetching lab list:", err));
  }, []);

  const handleCheckLab = async () => {
    setResult(null);
    setError("");

    if (!lab || !day || !period) {
      setError("Please select a Lab, Day, and Period.");
      return;
    }

    try {
      const response = await axios.get("http://localhost:5000/api/check-availability", {
        params: { room: lab, day, period },
      });
      console.log("Check Lab Response:", response.data);
      setResult(response.data);
    } catch (err) {
      console.error("Error checking lab availability:", err);
      setError("Lab not found or server error.");
    }
  };

  return (
    <div className="lab-search">
      <h2>Check Lab Availability</h2>

      <div className="search-filters">
        <div className="search-row">
          <label>Lab:</label>
          <select value={lab} onChange={(e) => setLab(e.target.value)}>
            {labList.map((l) => (
              <option key={l.name} value={l.name}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="search-row">
          <label>Day:</label>
          <select value={day} onChange={(e) => setDay(e.target.value)}>
            <option value="Monday">Monday</option>
            <option value="Tuesday">Tuesday</option>
            <option value="Wednesday">Wednesday</option>
            <option value="Thursday">Thursday</option>
            <option value="Friday">Friday</option>
            <option value="Saturday">Saturday</option>
          </select>
        </div>

        <div className="search-row">
          <label>Period (1-8):</label>
          <input type="number" min="1" max="8" value={period} onChange={(e) => setPeriod(e.target.value)} />
        </div>

        <div className="button-group">
          <button onClick={handleCheckLab}>Search</button>
          <button onClick={goBack}>Back</button>
        </div>
      </div>

      {error && <p className="error">{error}</p>}

      {result && (
        <div className="result">
          <h3>Lab Availability</h3>
          {result.message === "The classroom is occupied." ? (
            <>
              <p><strong>Status:</strong> Occupied</p>
              <p><strong>Room:</strong> {result.roomDetails.room}</p>
              <p><strong>Faculty:</strong> {result.roomDetails.faculty}</p>
              <p><strong>Subject:</strong> {result.roomDetails.subject}</p>
              <p><strong>Day:</strong> {day}</p>
              <p><strong>Period:</strong> {period}th Hour</p>
              <p><strong>Alternative Room:</strong> {result.alternativeRoom}</p>
            </>
          ) : (
            <p><strong>Status:</strong> Free</p>
          )}
        </div>
      )}
    </div>
  );
};

export default LabSearch;
